var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"칫……!","JPN":"ちっ……！","ENG":"Tch...!","TWN":"嘖……！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이번에도 분신이야?","JPN":"今回も分身なの？","ENG":"Another clone?","TWN":"這次又是分身嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"누군가 다칠 때까지 싸우고 싶진 않아요. 저희가 지나가게만 해 주세요.","JPN":"誰かが怪我をしてしまうほどの戦いはしたくありません。\\n私たちを行かせてください。","ENG":"I do not wish for anyone to get hurt. Just let us pass.","TWN":"我不希望有人受傷，請放我們離開。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"사적인 판단으로 용의자를 그냥 내버려 둘 것 같아?","JPN":"私的な判断で容疑者を野放しにするとでも？","ENG":"Do you really think we’ll let you go because you asked politely?","TWN":"你覺得我會因為有人跟我求情，就放過嫌犯嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"지금이야, 강소영 경위!","JPN":"今よ、マエカワ警部補！","ENG":"Now, Lieutenant Kang!","TWN":"就是現在，姜素英警衛！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네, 네~ 지금 갑니다~","JPN":"はいはい、今行きますよー！","ENG":"Yes ma’am! Coming!","TWN":"是，好～立刻過去～"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어, 어라……?","JPN":"あ、あれ……？","ENG":"E-err?","TWN":"嗯……？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지, 지아가 만든 분신들이 사라지고 있잖아?","JPN":"ユ、ユイちゃんが作った分身たちが消えていく？","ENG":"J-Jia’s clones are disappearing?","TWN":"小…小佳，你弄出來的分身一個一個消失中欸？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"도시관리국에서 받은 증강현실 간섭기예요.","JPN":"都市管理局からもらった拡張現実干渉機です。","ENG":"It’s City Managements’ augmented reality jammer.","TWN":"這是城市管理局提供的擴增實境干涉器。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"질량을 부여할 홀로그램이 유지되지 않으면 대표님 능력도 무용지물이라고 하더라고요.","JPN":"質量を付与するホログラムを維持できなければ、\\nヒメノ・ユイ代表の能力も無用の長物になるそうですね。","ENG":"I heard that your abilities are useless if they can’t hold matter.","TWN":"若是賦予質量的全息圖沒有維持住，代表你的能力也就無用武之處。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"죄……. 죄송해요. 세실리아 씨. 이대로는…….","JPN":"ご、ごめんなさい……セシリアさん。このままじゃ……","ENG":"I-I’m sorry, Cecilia... But at this rate...","TWN":"對……對不起，賽希莉亞，我……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지, 지아야! 안 된다! 아직은 안 돼!","JPN":"ユ、ユイちゃん！　ダメよ！　まだダメ！","ENG":"Jia! No! You can’t...!","TWN":"小…小佳！不可以！你還不可以消失！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"몸에 노이즈가 생기고 있어……?","JPN":"体にノイズが発生している……？","ENG":"Her body’s flickering...?","TWN":"體內有發出聲音……？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"설마 처음부터 전부 분신이었다는 거야?","JPN":"まさか、最初から全部分身だったってこと？","ENG":"It can’t be. Every single one was a clone?","TWN":"難道從一開始就全都是分身嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 아무래도 분신을 이 분한테 붙여 주고 단독으로 움직인 모양이네요.","JPN":"ええ。どうやら分身をこの方に付き添わせて、単独で動いていたようですね。","ENG":"It seems so. Looks like she placed a clone with her and decided to move alone.","TWN":"對，看來是調虎離山之計，是利用她來騙過我們。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이, 이 손 놔라!","JPN":"は、放しなさい！","ENG":"L-let go of me!","TWN":"放…放開我！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"일개 공무원 주제에! 내가 누군지 알고!","JPN":"一介の公務員の分際で！　私が誰なのか知っているの！？","ENG":"You lousy civil servant! Do you even know who I am?!","TWN":"一個區區的公務員！你們知道我是誰嗎！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러게요? 대체 누구실까요?","JPN":"確かに。いったい何者でしょうか？","ENG":"No, I don’t. Who are you?","TWN":"不知道，請問你是誰？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"누구신데 신지아 대표와 같이 다니고 계시는지 경찰서에서 천천히 들어 볼까요?","JPN":"いったいどちら様で、なぜヒメノ・ユイ代表と一緒に動いていたのか、\\n警察署でゆっくりお話を聞かせてくださいね。","ENG":"Who are you and why were you with Shin Jia? How about we go down to the station to answer some questions, hmm?","TWN":"還和沈佳代表一起行動，我們到警局裡慢慢說吧！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"커피 정도는 타 드릴 테니까요.","JPN":"コーヒーくらいは淹れてあげますから。","ENG":"I’ll even make you a cup of coffee.","TWN":"我還可以泡杯咖啡請你喝～"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그, 그건 안 돼! 나는 아직 지아를 놓칠 수 없단 말이다!","JPN":"ダ、ダメ！　私はまだユイを見守らないと！","ENG":"U-unacceptable! I can’t lose Jia like this!","TWN":"不可以！我還不能放棄小佳！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"세실리아 씨……!","JPN":"セシリアさん……！","ENG":"Cecilia!","TWN":"賽希莉亞……！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마지막으로 시간을 벌어 드릴게요! 도망치세요!","JPN":"最後に時間を稼ぎます！　逃げてください！","ENG":"I’ll try to buy you some time. Hurry! Run!","TWN":"這是我最後能為你爭取到的時間！你快逃！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"분신으로 폭발까지 일으킨다고? 이런……!","JPN":"しまった……！　分身で爆発まで起こせるの！？","ENG":"She can make her clones explode? Shoot...!","TWN":"分身竟然自爆？怎麼會……！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위! 일어설 수 있겠어?!","JPN":"マエカワ警部補！　立てそう？","ENG":"Lieutenant! Can you stand?!","TWN":"姜素英警衛！你站得起來嗎？！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아야야…….","JPN":"いたた……","ENG":"Ouch...","TWN":"哎唷喂呀……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"괜찮아요. 경정님 모시게 된 뒤로 이런 일이 한두 번도 아닌데요, 뭘.","JPN":"平気ですよ。警視様の部下になってからというもの、\\nこれくらい日常茶飯事ですし。","ENG":"I’m okay. It’s not my first rodeo after being with you.","TWN":"我沒事，自從和警政大人一起行動後，這種事是家常便飯啦～"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잠깐, 손목은 왜 이래? 퉁퉁 부었잖아?","JPN":"ちょっと、その手首はどうしたの？　パンパンに腫れてるじゃない！？","ENG":"Huh? Your wrist... It’s swollen!","TWN":"等等，你的手腕怎麼會這麼腫？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하……. 꼬마가 제 손을 뿌리칠 때 살짝 삐었나 보네요.","JPN":"あはは……さっきの子に腕を払われた時に捻挫したみたいです。","ENG":"Ahaha... I guess I sprained it when that kid pushed my hand away.","TWN":"哈哈……應該剛剛那個小鬼甩開我的手時，不小心扭了一下。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 꼬마가?","JPN":"あのチビが？","ENG":"Kid?","TWN":"那個小鬼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 꼬마라고 하기에는……. 힘이 보통이 아니더라고요?","JPN":"はい。チビというには……力が尋常ではなかったですけどね。","ENG":"Yes, but she was unusually strong for her age...","TWN":"對，不過她看起來雖然是個小鬼……力氣卻不是開玩笑的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"……이상할 정도로 말이에요.","JPN":"……本当に不思議なくらいに。","ENG":"It was almost unnatural.","TWN":"……力氣大到不可思。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"일단은…… 어떻게든 따돌렸나?","JPN":"とりあえずは……逃げられたみたいね。","ENG":"Did we lose them... for now?","TWN":"總算……把他們甩掉了吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하지만 지아의 분신도 없이 나 혼자 공장에 들어가 생산 이력을 확인하기엔…….","JPN":"でも、ユイちゃんの分身もないのに私一人で工場に入って\\n生産履歴を確認するには……","ENG":"But can I do this alone without one of Jia’s clones?","TWN":"可是沒有小佳的分身，我一個人要怎麼潛入工廠查履歷……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"거, 거기 누구냐!","JPN":"そ、そこにいるのは誰！？","ENG":"W-who’s there?!","TWN":"是…是誰！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"응? 아니, 넌……?","JPN":"あら？　君は……？","ENG":"Huh? Wait, aren’t you...?","TWN":"嗯？你不是……？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};